package com.cognizant.ems.controller; import java.util.*; import org.springframework.data.domain.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import com.cognizant.ems.model.*; import com.cognizant.ems.repository.*;
@RestController @RequestMapping("/employees") public class EmployeeController {final EmployeeRepository repo;EmployeeController(EmployeeRepository r){repo=r;}@GetMapping Page<Employee> all(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size,@RequestParam(defaultValue="id")String sort){return repo.findAll(PageRequest.of(page,size,Sort.by(sort)));}@GetMapping("/{id}")Employee get(@PathVariable Long id){return repo.findById(id).orElseThrow();}@PostMapping ResponseEntity<Employee> create(@RequestBody Employee e){return ResponseEntity.status(201).body(repo.save(e));}@PutMapping("/{id}")Employee update(@PathVariable Long id,@RequestBody Employee e){if(!repo.existsById(id))throw new NoSuchElementException();return repo.save(e);}@DeleteMapping("/{id}")void delete(@PathVariable Long id){repo.deleteById(id);}}
